            if (left < n && nums[i] > nums[left]) {
                return false;
            }

            // Calculate the index of the right child
            int right = 2 * i + 2;

            // If right child exists and is smaller than parent, not a min-heap
            if (right < n && nums[i] > nums[right]) {
                return false;
            }
        }

        // If no violations found, it is a min-heap
        return true;
    }
}

// Driver class
class Main {
